// fueldrop-website/src/components/AmountForm.jsx
import { useEffect, useRef, useState } from "react";
import "./AmountForm.css";

export default function AmountForm({ rentData, mobileNo, typeSet, amountInt, onSuccess, onError }) {
  const [amount] = useState(amountInt || 0);
  const [mobile, setMobile] = useState(mobileNo || "");
  const [isFrame, setIsFrame] = useState(false);
  const [keyGroup, setKeyGroup] = useState(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState("");
  const [retryCount, setRetryCount] = useState(0);
  const formRef = useRef(null);

  // ✅ Vegaah Gateway API Call
  const initiatePayment = async () => {
    if (!amount || amount < 10) {
      const errorMsg = "Amount must be at least ₹10";
      setError(errorMsg);
      if (onError) onError(errorMsg);
      return;
    }
    
    if (!mobile || mobile.length !== 10) {
      const errorMsg = "Valid 10-digit mobile number required";
      setError(errorMsg);
      if (onError) onError(errorMsg);
      return;
    }

    setIsLoading(true);
    setError("");

    try {
      // ✅ Use proxy if available, otherwise direct URL
      const apiUrl = process.env.REACT_APP_PAYMENT_API || "https://chagans.com/pg1/checkoutConc";
      
      console.log("Initiating payment with:", { amount, mobile, rentData });
      
      const response = await fetch(apiUrl, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "Accept": "application/json",
        },
        body: JSON.stringify({
          amount: amount,
          mobile: mobile,
          rentData: rentData,
          pgType: "fastag",
          apiType: "API",
          timestamp: new Date().toISOString(),
        }),
      });

      if (!response.ok) {
        throw new Error(`HTTP ${response.status}: ${response.statusText}`);
      }

      const data = await response.json();
      console.log("Payment API Response:", data);

      if (data.success && data.data) {
        setIsFrame(true);
        setKeyGroup(data.data);
        
        // Auto-submit to Vegaah Gateway
        setTimeout(() => {
          if (formRef.current) {
            formRef.current.submit();
          }
        }, 500);
        
        if (onSuccess) onSuccess(data);
      } else {
        const errorMsg = data.message || "Payment initialization failed";
        setError(errorMsg);
        if (onError) onError(errorMsg);
      }
    } catch (err) {
      console.error("Payment Error:", err);
      
      let errorMsg = "Payment failed. ";
      if (err.message.includes("Failed to fetch") || err.message.includes("Network")) {
        errorMsg += "Network error. Please check your connection and try again.";
      } else if (err.message.includes("CORS")) {
        errorMsg += "CORS policy blocked. Please contact support.";
      } else {
        errorMsg += err.message;
      }
      
      setError(errorMsg);
      // ✅ Call onError but DON'T set orderPlaced there
      if (onError) onError(errorMsg);
    } finally {
      setIsLoading(false);
    }
  };

  // Auto-trigger when props are ready
  useEffect(() => {
    if (amountInt && mobileNo && amountInt >= 10 && amountInt <= 50000) {
      initiatePayment();
    }
  }, [amountInt, mobileNo]);

  // Retry function
  const handleRetry = () => {
    setRetryCount(prev => prev + 1);
    initiatePayment();
  };

  return (
    <div className="fuel-payment-container">
      {!isFrame ? (
        <form onSubmit={(e) => { e.preventDefault(); initiatePayment(); }} className="fuel-payment-form">
          <div className="fuel-form-group">
            <label className="fuel-form-label">Amount to Pay (₹)</label>
            <input
              type="number"
              value={amount}
              readOnly
              disabled
              className="fuel-input-readonly"
            />
            <small className="fuel-hint">Amount is fixed and cannot be changed</small>
          </div>

          <div className="fuel-form-group">
            <label className="fuel-form-label">Mobile Number</label>
            <input
              type="tel"
              value={mobile}
              onChange={(e) => setMobile(e.target.value)}
              placeholder="Enter 10-digit mobile number"
              maxLength={10}
              required
              className="fuel-input"
              disabled={isLoading}
            />
            <small className="fuel-hint">Payment confirmation will be sent here</small>
          </div>

          {error && (
            <div className="fuel-error-message">
              <span>⚠️</span> 
              <div style={{ flex: 1 }}>{error}</div>
              <button 
                onClick={handleRetry} 
                style={{ 
                  background: '#dc2626', 
                  color: 'white', 
                  border: 'none', 
                  padding: '4px 12px', 
                  borderRadius: '20px',
                  cursor: 'pointer',
                  fontSize: '12px'
                }}
              >
                Retry
              </button>
            </div>
          )}

          <button 
            type="submit" 
            className="fuel-pay-button"
            disabled={isLoading || !amount || mobile.length !== 10}
          >
            {isLoading ? (
              <>
                <span className="fuel-spinner-small"></span>
                Processing...
              </>
            ) : (
              <>💳 Pay ₹{amount.toLocaleString('en-IN')}</>
            )}
          </button>

          <div className="fuel-secure-badge">
            <span>🔒</span> Secure payment via Vegaah Gateway
          </div>
          
          <div className="fuel-test-note" style={{ fontSize: '11px', color: '#999', textAlign: 'center', marginTop: '8px' }}>
            {process.env.NODE_ENV === 'development' && 'Test Mode: Gateway will open in production'}
          </div>
        </form>
      ) : (
        <div className="fuel-redirect-container">
          <form
            action={keyGroup?.APIURL}
            method="POST"
            ref={formRef}
          >
            {keyGroup &&
              Object.entries(keyGroup)
                .filter(([key]) => key !== "APIURL" && key !== "mobile")
                .map(([key, value]) => (
                  <input
                    type="hidden"
                    key={key}
                    name={key.toUpperCase()}
                    value={value}
                  />
                ))}
          </form>
          <div className="fuel-spinner"></div>
          <p className="fuel-redirect-text">Redirecting to Vegaah Payment Gateway...</p>
          <p className="fuel-redirect-note">Please wait, you'll be redirected to complete payment</p>
        </div>
      )}
    </div>
  );
}
